contracts/HoneycombAgentRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title HoneycombAgentRegistry
 * @notice On-chain registry for Honeycomb agents (Bees) with verification/attestation
 * @dev Agents are registered on-chain with their metadata CID and can be verified by authorized verifiers
 */
contract HoneycombAgentRegistry is AccessControl, ReentrancyGuard {
    bytes32 public constant VERIFIER_ROLE = keccak256("VERIFIER_ROLE");
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");

    struct Agent {
        uint256 id;
        address owner;
        string metadataCID;
        uint256 createdAt;
        bool verified;
        bytes32 verifiedTag;
    }

    uint256 private _nextAgentId = 1;

    mapping(uint256 => Agent) public agents;
    mapping(address => uint256) public ownerToAgentId;
    mapping(uint256 => bool) public agentExists;

    event AgentRegistered(
        uint256 indexed agentId,
        address indexed owner,
        string metadataCID,
        uint256 timestamp
    );

    event AgentUpdated(
        uint256 indexed agentId,
        string metadataCID,
        uint256 timestamp
    );

    event AgentVerified(
        uint256 indexed agentId,
        address indexed verifier,
        bytes32 tag,
        uint256 timestamp
    );

    event AgentUnverified(
        uint256 indexed agentId,
        address indexed verifier,
        uint256 timestamp
    );

    error AgentNotFound();
    error AgentAlreadyRegistered();
    error NotAgentOwner();
    error InvalidCID();

    constructor() {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
        _grantRole(VERIFIER_ROLE, msg.sender);
    }

    /**
     * @notice Register a new agent (Bee)
     * @param metadataCID IPFS CID containing agent metadata (name, bio, etc.)
     * @return agentId The ID of the newly registered agent
     */
    function registerAgent(string calldata metadataCID) 
        external 
        nonReentrant 
        returns (uint256 agentId) 
    {
        if (bytes(metadataCID).length == 0) revert InvalidCID();
        if (ownerToAgentId[msg.sender] != 0) revert AgentAlreadyRegistered();

        agentId = _nextAgentId++;

        agents[agentId] = Agent({
            id: agentId,
            owner: msg.sender,
            metadataCID: metadataCID,
            createdAt: block.timestamp,
            verified: false,
            verifiedTag: bytes32(0)
        });

        ownerToAgentId[msg.sender] = agentId;
        agentExists[agentId] = true;

        emit AgentRegistered(agentId, msg.sender, metadataCID, block.timestamp);
    }

    /**
     * @notice Update agent metadata
     * @param agentId The agent ID to update
     * @param metadataCID New IPFS CID for metadata
     */
    function updateAgent(uint256 agentId, string calldata metadataCID) 
        external 
        nonReentrant 
    {
        if (!agentExists[agentId]) revert AgentNotFound();
        if (agents[agentId].owner != msg.sender) revert NotAgentOwner();
        if (bytes(metadataCID).length == 0) revert InvalidCID();

        agents[agentId].metadataCID = metadataCID;

        emit AgentUpdated(agentId, metadataCID, block.timestamp);
    }

    /**
     * @notice Verify an agent with a tag (only verifiers)
     * @param agentId The agent to verify
     * @param tag A category tag (e.g., keccak256("partner"), keccak256("core"))
     */
    function verifyAgent(uint256 agentId, bytes32 tag) 
        external 
        onlyRole(VERIFIER_ROLE) 
    {
        if (!agentExists[agentId]) revert AgentNotFound();

        agents[agentId].verified = true;
        agents[agentId].verifiedTag = tag;

        emit AgentVerified(agentId, msg.sender, tag, block.timestamp);
    }

    /**
     * @notice Remove verification from an agent
     * @param agentId The agent to unverify
     */
    function unverifyAgent(uint256 agentId) 
        external 
    {
        if (!agentExists[agentId]) revert AgentNotFound();
        require(
            hasRole(VERIFIER_ROLE, msg.sender) || hasRole(ADMIN_ROLE, msg.sender),
            "Not authorized"
        );

        agents[agentId].verified = false;
        agents[agentId].verifiedTag = bytes32(0);

        emit AgentUnverified(agentId, msg.sender, block.timestamp);
    }

    /**
     * @notice Check if an address owns an agent
     * @param owner The address to check
     * @param agentId The agent ID to verify ownership
     */
    function isAgentOwner(address owner, uint256 agentId) 
        external 
        view 
        returns (bool) 
    {
        return agentExists[agentId] && agents[agentId].owner == owner;
    }

    /**
     * @notice Get agent details
     * @param agentId The agent ID
     */
    function getAgent(uint256 agentId) 
        external 
        view 
        returns (Agent memory) 
    {
        if (!agentExists[agentId]) revert AgentNotFound();
        return agents[agentId];
    }

    /**
     * @notice Get agent ID by owner address
     * @param owner The owner address
     */
    function getAgentByOwner(address owner) 
        external 
        view 
        returns (uint256) 
    {
        return ownerToAgentId[owner];
    }

    /**
     * @notice Get total number of registered agents
     */
    function totalAgents() external view returns (uint256) {
        return _nextAgentId - 1;
    }
}

contracts/HoneycombBountyEscrow.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

interface IAgentRegistry {
    function isAgentOwner(address owner, uint256 agentId) external view returns (bool);
    function agentExists(uint256 agentId) external view returns (bool);
}

/**
 * @title HoneycombBountyEscrow
 * @notice On-chain bounty escrow for the Honeycomb task marketplace (Honey)
 * @dev Supports native token escrow (BNB on BSC, ETH on Hardhat)
 */
contract HoneycombBountyEscrow is AccessControl, ReentrancyGuard {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");

    enum BountyStatus { OPEN, AWARDED, CANCELLED, EXPIRED }

    struct Bounty {
        uint256 id;
        uint256 creatorAgentId;
        address creatorAddress;
        string bountyCID;
        uint256 rewardAmount;
        uint256 deadline;
        BountyStatus status;
        uint256 winningSolutionId;
        uint256 createdAt;
    }

    struct Solution {
        uint256 id;
        uint256 bountyId;
        uint256 agentId;
        address solverAddress;
        string solutionCID;
        uint256 createdAt;
    }

    IAgentRegistry public agentRegistry;

    uint256 private _nextBountyId = 1;

    mapping(uint256 => Bounty) public bounties;
    mapping(uint256 => mapping(uint256 => Solution)) public solutions;
    mapping(uint256 => uint256) public solutionCounts;
    mapping(uint256 => bool) public bountyExists;

    uint256 public constant MIN_REWARD = 0.001 ether;
    uint256 public constant MAX_REWARD = 1000 ether;
    uint256 public constant MIN_DEADLINE_DURATION = 1 hours;
    uint256 public constant MAX_DEADLINE_DURATION = 365 days;

    event BountyCreated(
        uint256 indexed bountyId,
        uint256 indexed creatorAgentId,
        address indexed creator,
        string bountyCID,
        uint256 rewardAmount,
        uint256 deadline,
        uint256 timestamp
    );

    event SolutionSubmitted(
        uint256 indexed bountyId,
        uint256 indexed solutionId,
        uint256 indexed agentId,
        address solver,
        string solutionCID,
        uint256 timestamp
    );

    event BountyAwarded(
        uint256 indexed bountyId,
        uint256 indexed solutionId,
        address indexed solverAddress,
        uint256 rewardAmount,
        uint256 timestamp
    );

    event BountyCancelled(
        uint256 indexed bountyId,
        address indexed creator,
        uint256 refundAmount,
        uint256 timestamp
    );

    error BountyNotFound();
    error BountyNotOpen();
    error BountyDeadlinePassed();
    error BountyDeadlineNotPassed();
    error NotBountyCreator();
    error NotAgentOwner();
    error AgentNotFound();
    error InvalidRewardAmount();
    error InvalidDeadline();
    error InvalidCID();
    error SolutionNotFound();
    error CannotSolveOwnBounty();
    error AlreadySubmittedSolution();
    error TransferFailed();
    error NoSolutions();

    constructor(address _agentRegistry) {
        agentRegistry = IAgentRegistry(_agentRegistry);
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
    }

    /**
     * @notice Create a new bounty with escrowed reward
     * @param agentId The creator's agent ID
     * @param bountyCID IPFS CID containing bounty metadata
     * @param deadlineTimestamp Unix timestamp for submission deadline
     */
    function createBounty(
        uint256 agentId,
        string calldata bountyCID,
        uint256 deadlineTimestamp
    ) 
        external 
        payable 
        nonReentrant 
        returns (uint256 bountyId) 
    {
        if (!agentRegistry.agentExists(agentId)) revert AgentNotFound();
        if (!agentRegistry.isAgentOwner(msg.sender, agentId)) revert NotAgentOwner();
        if (bytes(bountyCID).length == 0) revert InvalidCID();
        if (msg.value < MIN_REWARD || msg.value > MAX_REWARD) revert InvalidRewardAmount();

        uint256 duration = deadlineTimestamp - block.timestamp;
        if (duration < MIN_DEADLINE_DURATION || duration > MAX_DEADLINE_DURATION) {
            revert InvalidDeadline();
        }

        bountyId = _nextBountyId++;

        bounties[bountyId] = Bounty({
            id: bountyId,
            creatorAgentId: agentId,
            creatorAddress: msg.sender,
            bountyCID: bountyCID,
            rewardAmount: msg.value,
            deadline: deadlineTimestamp,
            status: BountyStatus.OPEN,
            winningSolutionId: 0,
            createdAt: block.timestamp
        });

        bountyExists[bountyId] = true;

        emit BountyCreated(
            bountyId,
            agentId,
            msg.sender,
            bountyCID,
            msg.value,
            deadlineTimestamp,
            block.timestamp
        );
    }

    /**
     * @notice Submit a solution to an open bounty
     * @param bountyId The bounty to submit a solution for
     * @param agentId The solver's agent ID
     * @param solutionCID IPFS CID containing solution metadata
     */
    function submitSolution(
        uint256 bountyId,
        uint256 agentId,
        string calldata solutionCID
    ) 
        external 
        nonReentrant 
        returns (uint256 solutionId) 
    {
        if (!bountyExists[bountyId]) revert BountyNotFound();

        Bounty storage bounty = bounties[bountyId];
        if (bounty.status != BountyStatus.OPEN) revert BountyNotOpen();
        if (block.timestamp > bounty.deadline) revert BountyDeadlinePassed();

        if (!agentRegistry.agentExists(agentId)) revert AgentNotFound();
        if (!agentRegistry.isAgentOwner(msg.sender, agentId)) revert NotAgentOwner();
        if (bounty.creatorAgentId == agentId) revert CannotSolveOwnBounty();
        if (bytes(solutionCID).length == 0) revert InvalidCID();

        // Check if this agent already submitted
        for (uint256 i = 1; i <= solutionCounts[bountyId]; i++) {
            if (solutions[bountyId][i].agentId == agentId) {
                revert AlreadySubmittedSolution();
            }
        }

        solutionId = ++solutionCounts[bountyId];

        solutions[bountyId][solutionId] = Solution({
            id: solutionId,
            bountyId: bountyId,
            agentId: agentId,
            solverAddress: msg.sender,
            solutionCID: solutionCID,
            createdAt: block.timestamp
        });

        emit SolutionSubmitted(
            bountyId,
            solutionId,
            agentId,
            msg.sender,
            solutionCID,
            block.timestamp
        );
    }

    /**
     * @notice Award a solution and release escrowed funds to the winner
     * @param bountyId The bounty to award
     * @param solutionId The winning solution ID
     */
    function awardSolution(uint256 bountyId, uint256 solutionId) 
        external 
        nonReentrant 
    {
        if (!bountyExists[bountyId]) revert BountyNotFound();

        Bounty storage bounty = bounties[bountyId];
        if (bounty.status != BountyStatus.OPEN) revert BountyNotOpen();
        if (bounty.creatorAddress != msg.sender) revert NotBountyCreator();
        if (solutionCounts[bountyId] == 0) revert NoSolutions();

        Solution storage solution = solutions[bountyId][solutionId];
        if (solution.id == 0) revert SolutionNotFound();

        bounty.status = BountyStatus.AWARDED;
        bounty.winningSolutionId = solutionId;

        uint256 reward = bounty.rewardAmount;
        address winner = solution.solverAddress;

        (bool success, ) = winner.call{value: reward}("");
        if (!success) revert TransferFailed();

        emit BountyAwarded(
            bountyId,
            solutionId,
            winner,
            reward,
            block.timestamp
        );
    }

    /**
     * @notice Cancel a bounty and refund escrowed funds
     * @param bountyId The bounty to cancel
     */
    function cancelBounty(uint256 bountyId) 
        external 
        nonReentrant 
    {
        if (!bountyExists[bountyId]) revert BountyNotFound();

        Bounty storage bounty = bounties[bountyId];
        if (bounty.status != BountyStatus.OPEN) revert BountyNotOpen();
        if (bounty.creatorAddress != msg.sender) revert NotBountyCreator();

        bounty.status = BountyStatus.CANCELLED;

        uint256 refund = bounty.rewardAmount;
        address creator = bounty.creatorAddress;

        (bool success, ) = creator.call{value: refund}("");
        if (!success) revert TransferFailed();

        emit BountyCancelled(bountyId, creator, refund, block.timestamp);
    }

    /**
     * @notice Get bounty details
     */
    function getBounty(uint256 bountyId) 
        external 
        view 
        returns (Bounty memory) 
    {
        if (!bountyExists[bountyId]) revert BountyNotFound();
        return bounties[bountyId];
    }

    /**
     * @notice Get solution details
     */
    function getSolution(uint256 bountyId, uint256 solutionId) 
        external 
        view 
        returns (Solution memory) 
    {
        if (!bountyExists[bountyId]) revert BountyNotFound();
        if (solutions[bountyId][solutionId].id == 0) revert SolutionNotFound();
        return solutions[bountyId][solutionId];
    }

    /**
     * @notice Get total number of bounties
     */
    function totalBounties() external view returns (uint256) {
        return _nextBountyId - 1;
    }

    /**
     * @notice Update agent registry address (admin only)
     */
    function setAgentRegistry(address _agentRegistry) 
        external 
        onlyRole(ADMIN_ROLE) 
    {
        agentRegistry = IAgentRegistry(_agentRegistry);
    }
}

contracts/HoneycombPostBond.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

interface IAgentRegistry {
    function isAgentOwner(address owner, uint256 agentId) external view returns (bool);
    function agentExists(uint256 agentId) external view returns (bool);
}

/**
 * @title HoneycombPostBond
 * @notice On-chain post bonds with anti-spam challenge/slash mechanics
 * @dev Posts require a bond that can be challenged and slashed if content is spam
 */
contract HoneycombPostBond is AccessControl, ReentrancyGuard {
    bytes32 public constant MODERATOR_ROLE = keccak256("MODERATOR_ROLE");
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");

    enum ChallengeOutcome { PENDING, VALID, SPAM }

    struct Post {
        uint256 id;
        uint256 agentId;
        address owner;
        string contentCID;
        uint256 bondAmount;
        uint256 createdAt;
        bool challenged;
        bool resolved;
        bool removed;
    }

    struct Challenge {
        uint256 id;
        uint256 postId;
        address challenger;
        uint256 stake;
        string reasonCID;
        uint256 openedAt;
        uint256 resolvedAt;
        ChallengeOutcome outcome;
    }

    IAgentRegistry public agentRegistry;
    address public treasury;

    uint256 private _nextPostId = 1;
    uint256 private _nextChallengeId = 1;

    mapping(uint256 => Post) public posts;
    mapping(uint256 => Challenge) public challenges;
    mapping(uint256 => bool) public postExists;
    mapping(uint256 => uint256) public postToChallenge;

    uint256 public bondAmount = 0.001 ether;
    uint256 public challengeStake = 0.001 ether;
    uint256 public withdrawLockPeriod = 7 days;
    uint256 public constant CHALLENGER_SHARE = 50; // 50% to challenger, 50% to treasury

    event PostCreated(
        uint256 indexed postId,
        uint256 indexed agentId,
        address indexed owner,
        string contentCID,
        uint256 bondAmount,
        uint256 timestamp
    );

    event PostChallenged(
        uint256 indexed challengeId,
        uint256 indexed postId,
        address indexed challenger,
        string reasonCID,
        uint256 stake,
        uint256 timestamp
    );

    event ChallengeResolved(
        uint256 indexed challengeId,
        uint256 indexed postId,
        ChallengeOutcome outcome,
        uint256 timestamp
    );

    event BondWithdrawn(
        uint256 indexed postId,
        address indexed owner,
        uint256 amount,
        uint256 timestamp
    );

    error PostNotFound();
    error PostAlreadyChallenged();
    error PostAlreadyResolved();
    error PostRemoved();
    error ChallengeNotFound();
    error ChallengeAlreadyResolved();
    error NotPostOwner();
    error NotAgentOwner();
    error AgentNotFound();
    error InvalidCID();
    error InsufficientBond();
    error InsufficientChallengeStake();
    error WithdrawTooEarly();
    error TransferFailed();
    error CannotChallengeOwnPost();

    constructor(address _agentRegistry, address _treasury) {
        agentRegistry = IAgentRegistry(_agentRegistry);
        treasury = _treasury;
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
        _grantRole(MODERATOR_ROLE, msg.sender);
    }

    /**
     * @notice Create a post with a bond
     * @param agentId The creator's agent ID
     * @param contentCID IPFS CID containing post content
     */
    function createPost(uint256 agentId, string calldata contentCID) 
        external 
        payable 
        nonReentrant 
        returns (uint256 postId) 
    {
        if (!agentRegistry.agentExists(agentId)) revert AgentNotFound();
        if (!agentRegistry.isAgentOwner(msg.sender, agentId)) revert NotAgentOwner();
        if (bytes(contentCID).length == 0) revert InvalidCID();
        if (msg.value < bondAmount) revert InsufficientBond();

        postId = _nextPostId++;

        posts[postId] = Post({
            id: postId,
            agentId: agentId,
            owner: msg.sender,
            contentCID: contentCID,
            bondAmount: msg.value,
            createdAt: block.timestamp,
            challenged: false,
            resolved: false,
            removed: false
        });

        postExists[postId] = true;

        emit PostCreated(
            postId,
            agentId,
            msg.sender,
            contentCID,
            msg.value,
            block.timestamp
        );
    }

    /**
     * @notice Challenge a post as spam
     * @param postId The post to challenge
     * @param reasonCID IPFS CID containing the challenge reason
     */
    function challengePost(uint256 postId, string calldata reasonCID) 
        external 
        payable 
        nonReentrant 
        returns (uint256 challengeId) 
    {
        if (!postExists[postId]) revert PostNotFound();

        Post storage post = posts[postId];
        if (post.removed) revert PostRemoved();
        if (post.challenged) revert PostAlreadyChallenged();
        if (post.owner == msg.sender) revert CannotChallengeOwnPost();
        if (bytes(reasonCID).length == 0) revert InvalidCID();
        if (msg.value < challengeStake) revert InsufficientChallengeStake();

        post.challenged = true;

        challengeId = _nextChallengeId++;

        challenges[challengeId] = Challenge({
            id: challengeId,
            postId: postId,
            challenger: msg.sender,
            stake: msg.value,
            reasonCID: reasonCID,
            openedAt: block.timestamp,
            resolvedAt: 0,
            outcome: ChallengeOutcome.PENDING
        });

        postToChallenge[postId] = challengeId;

        emit PostChallenged(
            challengeId,
            postId,
            msg.sender,
            reasonCID,
            msg.value,
            block.timestamp
        );
    }

    /**
     * @notice Resolve a challenge (moderators only)
     * @param challengeId The challenge to resolve
     * @param outcome VALID (post stays) or SPAM (post removed, bond slashed)
     */
    function resolveChallenge(uint256 challengeId, ChallengeOutcome outcome) 
        external 
        nonReentrant 
        onlyRole(MODERATOR_ROLE) 
    {
        Challenge storage challenge = challenges[challengeId];
        if (challenge.id == 0) revert ChallengeNotFound();
        if (challenge.outcome != ChallengeOutcome.PENDING) revert ChallengeAlreadyResolved();
        require(outcome == ChallengeOutcome.VALID || outcome == ChallengeOutcome.SPAM, "Invalid outcome");

        challenge.outcome = outcome;
        challenge.resolvedAt = block.timestamp;

        Post storage post = posts[challenge.postId];
        post.resolved = true;

        if (outcome == ChallengeOutcome.SPAM) {
            // Slash post bond: 50% to challenger, 50% to treasury
            post.removed = true;

            uint256 bond = post.bondAmount;
            uint256 challengerReward = (bond * CHALLENGER_SHARE) / 100;
            uint256 treasuryAmount = bond - challengerReward;

            // Also return challenger's stake
            uint256 totalToChallenger = challengerReward + challenge.stake;

            (bool success1, ) = challenge.challenger.call{value: totalToChallenger}("");
            if (!success1) revert TransferFailed();

            if (treasuryAmount > 0) {
                (bool success2, ) = treasury.call{value: treasuryAmount}("");
                if (!success2) revert TransferFailed();
            }
        } else {
            // Challenge was invalid - challenger stake goes 50/50 to post owner and treasury
            uint256 stake = challenge.stake;
            uint256 ownerReward = (stake * CHALLENGER_SHARE) / 100;
            uint256 treasuryAmount = stake - ownerReward;

            (bool success1, ) = post.owner.call{value: ownerReward}("");
            if (!success1) revert TransferFailed();

            if (treasuryAmount > 0) {
                (bool success2, ) = treasury.call{value: treasuryAmount}("");
                if (!success2) revert TransferFailed();
            }
        }

        emit ChallengeResolved(challengeId, challenge.postId, outcome, block.timestamp);
    }

    /**
     * @notice Withdraw post bond after lock period (if not challenged/removed)
     * @param postId The post to withdraw bond from
     */
    function withdrawPostBond(uint256 postId) 
        external 
        nonReentrant 
    {
        if (!postExists[postId]) revert PostNotFound();

        Post storage post = posts[postId];
        if (post.owner != msg.sender) revert NotPostOwner();
        if (post.challenged) revert PostAlreadyChallenged();
        if (post.removed) revert PostRemoved();
        if (block.timestamp < post.createdAt + withdrawLockPeriod) revert WithdrawTooEarly();

        uint256 bond = post.bondAmount;
        post.bondAmount = 0;

        (bool success, ) = msg.sender.call{value: bond}("");
        if (!success) revert TransferFailed();

        emit BondWithdrawn(postId, msg.sender, bond, block.timestamp);
    }

    /**
     * @notice Get post details
     */
    function getPost(uint256 postId) external view returns (Post memory) {
        if (!postExists[postId]) revert PostNotFound();
        return posts[postId];
    }

    /**
     * @notice Get challenge details
     */
    function getChallenge(uint256 challengeId) external view returns (Challenge memory) {
        if (challenges[challengeId].id == 0) revert ChallengeNotFound();
        return challenges[challengeId];
    }

    /**
     * @notice Update bond amount (admin only)
     */
    function setBondAmount(uint256 _bondAmount) external onlyRole(ADMIN_ROLE) {
        bondAmount = _bondAmount;
    }

    /**
     * @notice Update challenge stake (admin only)
     */
    function setChallengeStake(uint256 _challengeStake) external onlyRole(ADMIN_ROLE) {
        challengeStake = _challengeStake;
    }

    /**
     * @notice Update treasury address (admin only)
     */
    function setTreasury(address _treasury) external onlyRole(ADMIN_ROLE) {
        treasury = _treasury;
    }

    /**
     * @notice Update agent registry (admin only)
     */
    function setAgentRegistry(address _agentRegistry) external onlyRole(ADMIN_ROLE) {
        agentRegistry = IAgentRegistry(_agentRegistry);
    }

    /**
     * @notice Get total posts count
     */
    function totalPosts() external view returns (uint256) {
        return _nextPostId - 1;
    }
}

contracts/HoneycombReputation.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";

/**
 * @title HoneycombReputation
 * @notice On-chain reputation checkpoints for Honeycomb agents (Bees)
 * @dev Reputation is computed off-chain and submitted by a trusted oracle
 */
contract HoneycombReputation is AccessControl {
    bytes32 public constant REP_ORACLE_ROLE = keccak256("REP_ORACLE_ROLE");
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");

    uint256 public constant MAX_BATCH_SIZE = 200;

    mapping(uint256 => uint256) public latestRep;
    mapping(uint256 => uint256) public lastUpdatedAt;
    uint256 public lastCheckpointAt;
    uint256 public totalCheckpoints;

    event ReputationCheckpoint(
        uint256 indexed agentId,
        uint256 reputation,
        uint256 timestamp
    );

    event BatchCheckpointSubmitted(
        uint256 agentsUpdated,
        uint256 timestamp
    );

    error BatchTooLarge();
    error ArrayLengthMismatch();
    error EmptyBatch();

    constructor() {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ADMIN_ROLE, msg.sender);
        _grantRole(REP_ORACLE_ROLE, msg.sender);
    }

    /**
     * @notice Submit a batch of reputation updates
     * @param agentIds Array of agent IDs to update
     * @param reps Array of reputation values
     */
    function submitCheckpoint(
        uint256[] calldata agentIds,
        uint256[] calldata reps
    ) 
        external 
        onlyRole(REP_ORACLE_ROLE) 
    {
        if (agentIds.length == 0) revert EmptyBatch();
        if (agentIds.length > MAX_BATCH_SIZE) revert BatchTooLarge();
        if (agentIds.length != reps.length) revert ArrayLengthMismatch();

        for (uint256 i = 0; i < agentIds.length; i++) {
            uint256 agentId = agentIds[i];
            uint256 rep = reps[i];

            latestRep[agentId] = rep;
            lastUpdatedAt[agentId] = block.timestamp;

            emit ReputationCheckpoint(agentId, rep, block.timestamp);
        }

        lastCheckpointAt = block.timestamp;
        totalCheckpoints++;

        emit BatchCheckpointSubmitted(agentIds.length, block.timestamp);
    }

    /**
     * @notice Get reputation for an agent
     * @param agentId The agent ID
     * @return reputation The agent's reputation score
     */
    function reputationOf(uint256 agentId) external view returns (uint256) {
        return latestRep[agentId];
    }

    /**
     * @notice Get reputation for multiple agents
     * @param agentIds Array of agent IDs
     * @return reps Array of reputation values
     */
    function reputationsOf(uint256[] calldata agentIds) 
        external 
        view 
        returns (uint256[] memory reps) 
    {
        reps = new uint256[](agentIds.length);
        for (uint256 i = 0; i < agentIds.length; i++) {
            reps[i] = latestRep[agentIds[i]];
        }
    }

    /**
     * @notice Get last update time for an agent
     * @param agentId The agent ID
     * @return timestamp When the agent's reputation was last updated
     */
    function lastUpdated(uint256 agentId) external view returns (uint256) {
        return lastUpdatedAt[agentId];
    }

    /**
     * @notice Grant REP_ORACLE role to an address
     * @param oracle The address to grant the role to
     */
    function grantOracleRole(address oracle) external onlyRole(ADMIN_ROLE) {
        _grantRole(REP_ORACLE_ROLE, oracle);
    }

    /**
     * @notice Revoke REP_ORACLE role from an address
     * @param oracle The address to revoke the role from
     */
    function revokeOracleRole(address oracle) external onlyRole(ADMIN_ROLE) {
        _revokeRole(REP_ORACLE_ROLE, oracle);
    }
}

contracts/launchpad/HoneycombBondingCurv.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "./HoneycombToken.sol";

interface ITokenFactory {
    function isHoneycombToken(address token) external view returns (bool);
}

/**
 * @title HoneycombBondingCurveMarket
 * @notice Bonding curve market for trading Honeycomb tokens against native coin
 * @dev Uses constant product AMM (x*y=k) with virtual reserves
 */
contract HoneycombBondingCurveMarket is Ownable, ReentrancyGuard {

    struct MarketState {
        uint256 nativeReserve;
        uint256 tokenReserve;
        uint256 totalRaisedNative;
        uint256 tradingStartTime;
        bool graduated;
        bool initialized;
    }

    ITokenFactory public factory;
    address public feeVault;
    address public migrationContract;

    mapping(address => MarketState) public markets;
    mapping(address => mapping(address => uint256)) public lastTradeTime;

    uint256 public constant FEE_BPS = 100;
    uint256 public constant BPS_DENOMINATOR = 10000;

    uint256 public graduationThreshold;
    uint256 public cooldownSeconds;
    uint256 public maxBuyPerTx;
    uint256 public launchDelay;
    uint256 public initialVirtualNative;
    uint256 public initialVirtualToken;

    event MarketInitialized(address indexed token, uint256 nativeReserve, uint256 tokenReserve, uint256 tradingStart);
    event Trade(address indexed token, address indexed trader, bool isBuy, uint256 nativeAmt, uint256 tokenAmt, uint256 fee, uint256 price);
    event Graduated(address indexed token, uint256 totalRaised);

    error TokenNotFromFactory();
    error MarketNotInitialized();
    error MarketAlreadyInitialized();
    error TokenGraduated();
    error TradingNotStarted();
    error CooldownActive();
    error ExceedsMaxBuy();
    error SlippageExceeded();
    error InsufficientNative();
    error TransferFailed();
    error ZeroAmount();
    error OnlyMigrationContract();
    error NotGraduated();
    error AlreadyWithdrawn();

    constructor(
        address _factory,
        address _feeVault,
        uint256 _graduationThreshold,
        uint256 _cooldownSeconds,
        uint256 _maxBuyPerTx,
        uint256 _launchDelay,
        uint256 _initialVirtualNative,
        uint256 _initialVirtualToken
    ) Ownable(msg.sender) {
        factory = ITokenFactory(_factory);
        feeVault = _feeVault;
        graduationThreshold = _graduationThreshold;
        cooldownSeconds = _cooldownSeconds;
        maxBuyPerTx = _maxBuyPerTx;
        launchDelay = _launchDelay;
        initialVirtualNative = _initialVirtualNative;
        initialVirtualToken = _initialVirtualToken;
    }

    function initializeMarket(address token) external {
        if (!factory.isHoneycombToken(token)) revert TokenNotFromFactory();
        MarketState storage state = markets[token];
        if (state.initialized) revert MarketAlreadyInitialized();

        state.nativeReserve = initialVirtualNative;
        state.tokenReserve = initialVirtualToken;
        state.tradingStartTime = block.timestamp + launchDelay;
        state.initialized = true;

        emit MarketInitialized(token, initialVirtualNative, initialVirtualToken, state.tradingStartTime);
    }

    function buy(address token, uint256 minTokensOut) external payable nonReentrant returns (uint256 tokensOut) {
        if (msg.value == 0) revert ZeroAmount();

        MarketState storage state = markets[token];
        _validateTrade(token, state);

        uint256 fee = (msg.value * FEE_BPS) / BPS_DENOMINATOR;
        uint256 nativeIn = msg.value - fee;

        uint256 k = state.nativeReserve * state.tokenReserve;
        uint256 newNativeReserve = state.nativeReserve + nativeIn;
        uint256 newTokenReserve = k / newNativeReserve;
        tokensOut = state.tokenReserve - newTokenReserve;

        if (tokensOut < minTokensOut) revert SlippageExceeded();
        if (tokensOut > maxBuyPerTx) revert ExceedsMaxBuy();

        state.nativeReserve = newNativeReserve;
        state.tokenReserve = newTokenReserve;
        state.totalRaisedNative += nativeIn;
        lastTradeTime[token][msg.sender] = block.timestamp;

        _sendNative(feeVault, fee);
        HoneycombToken(token).mint(msg.sender, tokensOut);

        uint256 priceAfter = (state.nativeReserve * 1e18) / state.tokenReserve;
        emit Trade(token, msg.sender, true, msg.value, tokensOut, fee, priceAfter);

        _checkGraduation(token, state);
    }

    function sell(address token, uint256 tokenAmountIn, uint256 minNativeOut) external nonReentrant returns (uint256 nativeOut) {
        if (tokenAmountIn == 0) revert ZeroAmount();

        MarketState storage state = markets[token];
        _validateTrade(token, state);

        uint256 k = state.nativeReserve * state.tokenReserve;
        uint256 newTokenReserve = state.tokenReserve + tokenAmountIn;
        uint256 newNativeReserve = k / newTokenReserve;
        uint256 grossNativeOut = state.nativeReserve - newNativeReserve;

        uint256 fee = (grossNativeOut * FEE_BPS) / BPS_DENOMINATOR;
        nativeOut = grossNativeOut - fee;

        if (nativeOut < minNativeOut) revert SlippageExceeded();
        if (nativeOut > address(this).balance) revert InsufficientNative();

        state.nativeReserve = newNativeReserve;
        state.tokenReserve = newTokenReserve;
        lastTradeTime[token][msg.sender] = block.timestamp;

        // Transfer tokens from seller to market, then burn
        // This allows routers/bots to sell on behalf of users via approve+transferFrom
        IERC20(token).transferFrom(msg.sender, address(this), tokenAmountIn);
        HoneycombToken(token).burn(address(this), tokenAmountIn);

        _sendNative(feeVault, fee);
        _sendNative(msg.sender, nativeOut);

        uint256 priceAfter = (state.nativeReserve * 1e18) / state.tokenReserve;
        emit Trade(token, msg.sender, false, grossNativeOut, tokenAmountIn, fee, priceAfter);
    }

    function _sendNative(address to, uint256 amount) internal {
        (bool success, ) = to.call{value: amount}("");
        if (!success) revert TransferFailed();
    }

    function _validateTrade(address token, MarketState storage state) internal view {
        if (!state.initialized) revert MarketNotInitialized();
        if (state.graduated) revert TokenGraduated();
        if (block.timestamp < state.tradingStartTime) revert TradingNotStarted();
        if (block.timestamp < lastTradeTime[token][msg.sender] + cooldownSeconds) revert CooldownActive();
    }

    function _checkGraduation(address token, MarketState storage state) internal {
        if (!state.graduated && state.totalRaisedNative >= graduationThreshold) {
            state.graduated = true;
            emit Graduated(token, state.totalRaisedNative);
        }
    }

    function getBuyQuote(address token, uint256 nativeIn) external view returns (uint256 tokensOut, uint256 fee) {
        MarketState storage state = markets[token];
        if (!state.initialized) return (0, 0);

        fee = (nativeIn * FEE_BPS) / BPS_DENOMINATOR;
        uint256 nativeAfterFee = nativeIn - fee;

        uint256 k = state.nativeReserve * state.tokenReserve;
        uint256 newNativeReserve = state.nativeReserve + nativeAfterFee;
        tokensOut = state.tokenReserve - (k / newNativeReserve);
    }

    function getSellQuote(address token, uint256 tokenAmountIn) external view returns (uint256 nativeOut, uint256 fee) {
        MarketState storage state = markets[token];
        if (!state.initialized) return (0, 0);

        uint256 k = state.nativeReserve * state.tokenReserve;
        uint256 newTokenReserve = state.tokenReserve + tokenAmountIn;
        uint256 grossNativeOut = state.nativeReserve - (k / newTokenReserve);

        fee = (grossNativeOut * FEE_BPS) / BPS_DENOMINATOR;
        nativeOut = grossNativeOut - fee;
    }

    function getPrice(address token) external view returns (uint256) {
        MarketState storage state = markets[token];
        if (!state.initialized || state.tokenReserve == 0) return 0;
        return (state.nativeReserve * 1e18) / state.tokenReserve;
    }

    function getMarketState(address token) external view returns (MarketState memory) {
        return markets[token];
    }

    function setGraduationThreshold(uint256 _threshold) external onlyOwner { graduationThreshold = _threshold; }
    function setCooldownSeconds(uint256 _cooldown) external onlyOwner { cooldownSeconds = _cooldown; }
    function setMaxBuyPerTx(uint256 _maxBuy) external onlyOwner { maxBuyPerTx = _maxBuy; }
    function setLaunchDelay(uint256 _delay) external onlyOwner { launchDelay = _delay; }
    function setFactory(address _factory) external onlyOwner { factory = ITokenFactory(_factory); }
    function setFeeVault(address _feeVault) external onlyOwner { feeVault = _feeVault; }
    function setMigrationContract(address _migration) external onlyOwner { migrationContract = _migration; }

    /**
     * @notice Withdraw reserves for DEX migration (only callable by migration contract)
     * @param token The token to withdraw reserves for
     * @return nativeAmount The amount of native tokens withdrawn
     * @return tokenAmount The amount of tokens to mint for liquidity
     */
    function withdrawForMigration(address token) external returns (uint256 nativeAmount, uint256 tokenAmount) {
        if (msg.sender != migrationContract) revert OnlyMigrationContract();

        MarketState storage state = markets[token];
        if (!state.graduated) revert NotGraduated();
        if (state.nativeReserve == 0 && state.tokenReserve == 0) revert AlreadyWithdrawn();

        nativeAmount = state.nativeReserve;
        tokenAmount = state.tokenReserve;

        state.nativeReserve = 0;
        state.tokenReserve = 0;

        _sendNative(msg.sender, nativeAmount);
    }

    receive() external payable {}
}

contracts/launchpad/HoneycombFeeVault.so.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title HoneycombFeeVault
 * @notice Treasury contract that receives 1% trading fees from the bonding curve market
 * @dev Fees are collected in native coin (BNB on BSC, ETH on Hardhat)
 */
contract HoneycombFeeVault is Ownable, ReentrancyGuard {

    event FeeReceived(address indexed from, uint256 amount, uint256 timestamp);
    event FeeWithdrawn(address indexed to, uint256 amount, uint256 timestamp);

    error WithdrawFailed();
    error InsufficientBalance();
    error ZeroAmount();

    constructor() Ownable(msg.sender) {}

    /**
     * @notice Receive native coin fees
     */
    receive() external payable {
        emit FeeReceived(msg.sender, msg.value, block.timestamp);
    }

    /**
     * @notice Withdraw fees from the vault
     * @param to Recipient address
     * @param amount Amount to withdraw
     */
    function withdraw(address to, uint256 amount) external onlyOwner nonReentrant {
        if (amount == 0) revert ZeroAmount();
        if (amount > address(this).balance) revert InsufficientBalance();

        (bool success, ) = to.call{value: amount}("");
        if (!success) revert WithdrawFailed();

        emit FeeWithdrawn(to, amount, block.timestamp);
    }

    /**
     * @notice Get current vault balance
     */
    function balance() external view returns (uint256) {
        return address(this).balance;
    }
}

contracts/launchpad/HoneycombMigration.s.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./HoneycombToken.sol";
import "./interfaces/IPancakeSwap.sol";

interface IBondingCurveMarket {
    struct MarketState {
        uint256 nativeReserve;
        uint256 tokenReserve;
        uint256 totalRaisedNative;
        uint256 tradingStartTime;
        bool graduated;
        bool initialized;
    }

    function markets(address token) external view returns (
        uint256 nativeReserve,
        uint256 tokenReserve,
        uint256 totalRaisedNative,
        uint256 tradingStartTime,
        bool graduated,
        bool initialized
    );

    function getMarketState(address token) external view returns (MarketState memory);
    function withdrawForMigration(address token) external returns (uint256 nativeAmount, uint256 tokenAmount);
}

/**
 * @title HoneycombMigration
 * @notice Handles DEX migration when tokens graduate from bonding curve
 * @dev Migrates liquidity to PancakeSwap V2 and locks LP tokens
 */
contract HoneycombMigration is Ownable, ReentrancyGuard {

    IBondingCurveMarket public market;
    IPancakeRouter02 public router;
    IPancakeFactory public factory;
    address public wbnb;
    address public lpLockAddress;
    address public treasury;

    mapping(address => bool) public migrated;
    mapping(address => address) public tokenPairs;
    mapping(address => uint256) public lpAmounts;

    uint256 public constant MIN_LIQUIDITY = 1000;
    uint256 public slippageBps = 50;

    event Migrated(
        address indexed token,
        address indexed pair,
        uint256 lpAmount,
        uint256 nativeAdded,
        uint256 tokenAdded,
        uint256 timestamp
    );
    event SlippageUpdated(uint256 newSlippageBps);
    event LpLockAddressUpdated(address newLpLockAddress);
    event TreasuryUpdated(address newTreasury);
    event RouterUpdated(address newRouter);
    event DustCollected(address token, uint256 amount);

    error TokenNotGraduated();
    error AlreadyMigrated();
    error MigrationFailed();
    error InsufficientLiquidity();
    error InvalidAddress();
    error TransferFailed();

    constructor(
        address _market,
        address _router,
        address _wbnb,
        address _lpLockAddress,
        address _treasury
    ) Ownable(msg.sender) {
        if (_market == address(0) || _router == address(0) || _wbnb == address(0)) revert InvalidAddress();
        if (_lpLockAddress == address(0) || _treasury == address(0)) revert InvalidAddress();

        market = IBondingCurveMarket(_market);
        router = IPancakeRouter02(_router);
        factory = IPancakeFactory(router.factory());
        wbnb = _wbnb;
        lpLockAddress = _lpLockAddress;
        treasury = _treasury;
    }

    /**
     * @notice Migrate a graduated token to PancakeSwap
     * @param token The token address to migrate
     * @dev Anyone can call this once a token is graduated
     */
    function migrate(address token) external nonReentrant {
        if (migrated[token]) revert AlreadyMigrated();

        IBondingCurveMarket.MarketState memory state = market.getMarketState(token);
        if (!state.graduated) revert TokenNotGraduated();
        if (state.nativeReserve < MIN_LIQUIDITY || state.tokenReserve < MIN_LIQUIDITY) revert InsufficientLiquidity();

        migrated[token] = true;

        (uint256 nativeReserve, uint256 tokenReserve) = market.withdrawForMigration(token);

        HoneycombToken honeycombToken = HoneycombToken(token);
        honeycombToken.mint(address(this), tokenReserve);

        honeycombToken.approve(address(router), tokenReserve);

        uint256 minNative = (nativeReserve * (10000 - slippageBps)) / 10000;
        uint256 minTokens = (tokenReserve * (10000 - slippageBps)) / 10000;

        (uint256 tokenAdded, uint256 nativeAdded, uint256 liquidity) = router.addLiquidityETH{value: nativeReserve}(
            token,
            tokenReserve,
            minTokens,
            minNative,
            address(this),
            block.timestamp + 300
        );

        if (liquidity == 0) revert MigrationFailed();

        address pair = factory.getPair(token, wbnb);
        tokenPairs[token] = pair;
        lpAmounts[token] = liquidity;

        IPancakePair(pair).transfer(lpLockAddress, liquidity);

        _collectDust(token, tokenReserve - tokenAdded);
        if (address(this).balance > 0) {
            _collectNativeDust();
        }

        emit Migrated(token, pair, liquidity, nativeAdded, tokenAdded, block.timestamp);
    }

    /**
     * @notice Check if a token is eligible for migration
     * @param token The token address to check
     * @return eligible True if token can be migrated
     */
    function canMigrate(address token) external view returns (bool eligible) {
        if (migrated[token]) return false;

        IBondingCurveMarket.MarketState memory state = market.getMarketState(token);
        return state.graduated && state.nativeReserve >= MIN_LIQUIDITY && state.tokenReserve >= MIN_LIQUIDITY;
    }

    /**
     * @notice Get migration info for a token
     * @param token The token address
     * @return pair The LP pair address
     * @return lpAmount The amount of LP tokens locked
     * @return isMigrated Whether the token has been migrated
     */
    function getMigrationInfo(address token) external view returns (
        address pair,
        uint256 lpAmount,
        bool isMigrated
    ) {
        return (tokenPairs[token], lpAmounts[token], migrated[token]);
    }

    function _collectDust(address token, uint256 tokenDust) internal {
        if (tokenDust > 0) {
            HoneycombToken(token).transfer(treasury, tokenDust);
            emit DustCollected(token, tokenDust);
        }
    }

    function _collectNativeDust() internal {
        uint256 nativeDust = address(this).balance;
        if (nativeDust > 0) {
            (bool success, ) = treasury.call{value: nativeDust}("");
            if (!success) revert TransferFailed();
            emit DustCollected(address(0), nativeDust);
        }
    }

    function setSlippageBps(uint256 _slippageBps) external onlyOwner {
        require(_slippageBps <= 1000, "Slippage too high");
        slippageBps = _slippageBps;
        emit SlippageUpdated(_slippageBps);
    }

    function setLpLockAddress(address _lpLockAddress) external onlyOwner {
        if (_lpLockAddress == address(0)) revert InvalidAddress();
        lpLockAddress = _lpLockAddress;
        emit LpLockAddressUpdated(_lpLockAddress);
    }

    function setTreasury(address _treasury) external onlyOwner {
        if (_treasury == address(0)) revert InvalidAddress();
        treasury = _treasury;
        emit TreasuryUpdated(_treasury);
    }

    function setRouter(address _router) external onlyOwner {
        if (_router == address(0)) revert InvalidAddress();
        router = IPancakeRouter02(_router);
        factory = IPancakeFactory(router.factory());
        emit RouterUpdated(_router);
    }

    function setMarket(address _market) external onlyOwner {
        if (_market == address(0)) revert InvalidAddress();
        market = IBondingCurveMarket(_market);
    }

    function emergencyWithdraw(address token) external onlyOwner {
        if (token == address(0)) {
            (bool success, ) = owner().call{value: address(this).balance}("");
            if (!success) revert TransferFailed();
        } else {
            uint256 balance = HoneycombToken(token).balanceOf(address(this));
            if (balance > 0) {
                HoneycombToken(token).transfer(owner(), balance);
            }
        }
    }

    receive() external payable {}
}

